const cfg = $('Meeting Reminder Config').item.json;
const trackerItems = $('Query 24h Eligible Trackers').all();
const leadItems = $input.all();
const results = [];
const logoHtml = '<img src="https://example.com/logo-placeholder.png" alt="Example Company" width="200" style="display:block;border:0;margin-bottom:8px;" />';
for (let i = 0; i < trackerItems.length; i++) {
  const tracker = trackerItems[i].json;
  const lead = leadItems[i] ? leadItems[i].json : {};
  const tz = tracker.Meeting_Timezone__c || 'America/Los_Angeles';
  let readableDateTime = tracker.Meeting_Start_Date_Time__c || '';
  try {
    const dt = new Date(tracker.Meeting_Start_Date_Time__c);
    readableDateTime = dt.toLocaleString('en-US', {
      timeZone: tz, weekday: 'long', year: 'numeric', month: 'long',
      day: 'numeric', hour: 'numeric', minute: '2-digit', timeZoneName: 'short'
    });
  } catch(e) {}
  const firstName = String(lead.FirstName || lead.Name || 'there');
  const leadEmail = String(tracker.Lead_Email__c || lead.Email || '');
  const toAddress = cfg.testMode === true ? String(cfg.testRecipientOverride || 'user@example.com') : leadEmail;
  const ccList = cfg.senderEmail + ',' + cfg.colleagueEmail;
  const subject = "Tomorrow's Meeting with Example Company";
  const bodyHtml =
    '<p>Hi ' + firstName + ',</p>'
    + '<p>We\u2019re looking forward to connect with you tomorrow and learn more about your company.</p>'
    + '<p>Your meeting with Example Company is scheduled for:</p>'
    + '<p><strong>' + readableDateTime + '</strong></p>'
    + '<p>Example User, Founder &amp; CEO, and Example Representative, Business Development Representative, will be joining the call. The conversation will be a chance to better understand your current priorities, the types of properties or accounts you\u2019re focused on, and where our team may be able to help.</p>'
    + '<p>No preparation is needed ahead of the meeting. We simply look forward to getting to know your needs and seeing whether Example Company may be a good fit.</p>'
    + '<p>Please don\u2019t hesitate to reach out if anything comes up before tomorrow\u2019s call.</p>'
    + '<p>Best regards,</p>'
    + '<p>' + logoHtml + '</p>'
    + '<p>Example User<br>Founder &amp; CEO<br>user@example.com<br>O 555 010 0001 &nbsp; M 555 010 0002<br><a href="https://example.com">example.com</a><br><a href="https://calendly.com/example-user">Book a meeting here</a></p>'
    + '<p>Example Representative<br>Business Development Representative<br>Example Company<br>555-010-0000</p>';
  results.push({ json: {
    trackerId: String(tracker.Id || ''),
    leadId: String(tracker.Related_Lead__c || ''),
    leadEmail, firstName, toAddress, ccList, subject, bodyHtml, readableDateTime,
    reminderType: '24h', testMode: cfg.testMode === true, draftMode: cfg.draftMode === true,
    senderEmail: String(cfg.senderEmail || ''), colleagueEmail: String(cfg.colleagueEmail || '')
  }});
}
return results.length > 0 ? results : [{ json: { noEligible: true } }];

