    + '<p>Example User, Founder &amp; CEO, and Example Representative, Business Development Representative, look forward to learning more about your organization, portfolio, and current priorities.</p>'
    + '<p>The meeting will be an informal conversation to better understand your goals, challenges, and where Example Company may be able to support your business.</p>'
    + '<p>If you have any questions before the meeting, please feel free to reach out.</p>'
    + '<p>Best regards,</p>'
    + '<p>' + logoHtml + '</p>'
    + '<p>Example User<br>Founder &amp; CEO<br>user@example.com<br>O 555 010 0001 &nbsp; M 555 010 0002<br><a href="https://example.com">example.com</a><br><a href="https://calendly.com/example-user">Book a meeting here</a></p>'
    + '<p>Example Representative<br>Business Development Representative<br>Example Company<br>555-010-0000</p>';
  results.push({ json: {
    trackerId: String(tracker.Id || ''),
    leadId: String(tracker.Related_Lead__c || ''),
    leadEmail, firstName, toAddress, ccList, subject, bodyHtml, readableDateTime,
    reminderType: '1h', testMode: cfg.testMode === true, draftMode: cfg.draftMode === true,
