return results.length > 0 ? results : [{ json: { noEligible: true } }];

// Guard: only allow 24h reminder to send if meeting is NOT today
// and is still at least 20 hours away.
// Receives items from Format 24h Email (one per tracker).
const now = Date.now();
const TWENTY_HOURS_MS = 20 * 60 * 60 * 1000;
const results = [];

for (const item of $input.all()) {
  const ctx = item.json;
  // Pass-through noEligible items (empty batch)
  if (ctx.noEligible) {
    results.push({ json: { ...ctx } });
    continue;
  }

  // Get meeting start from tracker (stored in Format 24h Email output via trackerItems)
  // Format 24h Email doesn't carry meetingStartISO directly, so we re-read from
  // Query 24h Eligible Trackers by matching trackerId.
  let meetingStartISO = null;
  let meetingTz = 'America/Los_Angeles';
  try {
    const trackerItems = $('Query 24h Eligible Trackers').all();
    for (const t of trackerItems) {
      if (String(t.json.Id || '') === String(ctx.trackerId || '')) {
        meetingStartISO = String(t.json.Meeting_Start_Date_Time__c || '');
        meetingTz = String(t.json.Meeting_Timezone__c || 'America/Los_Angeles');
        break;
      }
    }
    // Fallback: positional match if Id not found (single-item batch)
    if (!meetingStartISO && trackerItems.length > 0) {
      meetingStartISO = String(trackerItems[0].json.Meeting_Start_Date_Time__c || '');
      meetingTz = String(trackerItems[0].json.Meeting_Timezone__c || 'America/Los_Angeles');
    }
  } catch(e) {}

  if (!meetingStartISO) {
    // Can't validate — skip safely
    results.push({ json: { noEligible: true, skipReason: '24h skipped: could not determine meeting start time' } });
    continue;
  }

  const meetingStart = new Date(meetingStartISO).getTime();
  const hoursUntilMeeting = (meetingStart - now) / (60 * 60 * 1000);

  // Check: is the meeting today in the meeting timezone?
  const todayInTz = new Date().toLocaleDateString('en-CA', { timeZone: meetingTz }); // YYYY-MM-DD
  const meetingDateInTz = new Date(meetingStartISO).toLocaleDateString('en-CA', { timeZone: meetingTz });
  const isMeetingToday = (todayInTz === meetingDateInTz);

  if (isMeetingToday) {
    results.push({ json: { noEligible: true, skipReason: '24h skipped: meeting is today (' + meetingDateInTz + ') in timezone ' + meetingTz } });
    continue;
  }

  if (hoursUntilMeeting < 20) {
    results.push({ json: { noEligible: true, skipReason: '24h skipped: meeting is only ' + hoursUntilMeeting.toFixed(1) + 'h away (< 20h threshold)' } });
    continue;
  }

  if (meetingStart <= now) {
    results.push({ json: { noEligible: true, skipReason: '24h skipped: meeting is in the past' } });
    continue;
  }

  // All checks passed — allow send
  results.push({ json: { ...ctx } });
}

return results.length > 0 ? results : [{ json: { noEligible: true } }];

// W12 RSVP / Event Guard — 24h branch
// Updated 2026-07-07: RSVP check removed per current policy (W12A aligned).
// Blocks send if: event missing, cancelled, lead not found in attendees, or time mismatch.
// Does NOT block on RSVP status (none/tentative/declined are now allowed).
// Item matching is key-based (iCalUID join), not positional — safe when Outlook drops items.

const INTERNAL_EMAILS = ['user@example.com', 'colleague@example.com'];
const TIME_TOLERANCE_SEC = 60;

const formatItems = $('Format 24h Email').all();
const trackerItems = $('Query 24h Eligible Trackers').all();
const outlookItems = $input.all();

const results = [];

for (let i = 0; i < formatItems.length; i++) {
  const fmt = formatItems[i].json;

  if (fmt.noEligible) {
    results.push({ json: { ...fmt } });
    continue;
  }

  const tracker = trackerItems.find(t => String(t.json.Id || '') === String(fmt.trackerId || ''));
  if (!tracker) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: tracker not found for id ' + fmt.trackerId } });
    continue;
  }

  const iCalUID = String(tracker.json.Outlook_Event_ID__c || '').trim();
  const leadEmail = String(tracker.json.Lead_Email__c || fmt.leadEmail || '').trim().toLowerCase();
  const sfStartISO = String(tracker.json.Meeting_Start_Date_Time__c || '');

  if (!iCalUID) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: Outlook_Event_ID__c is empty — cannot verify event' } });
    continue;
  }

  if (!leadEmail) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: Lead_Email__c is empty — cannot verify attendee' } });
    continue;
  }

  const matchingEvents = outlookItems.filter(item =>
    String(item.json.iCalUId || '').trim() === iCalUID
  );

  if (matchingEvents.length === 0) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: no Outlook event found for iCalUID — event may be deleted or missing. W12A will sync status.' } });
    continue;
  }

  if (matchingEvents.length > 1) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: ' + matchingEvents.length + ' Outlook events matched iCalUID — ambiguous, blocking reminder.' } });
    continue;
  }

  const liveEvent = matchingEvents[0].json;

  if (liveEvent.isCancelled === true) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: Outlook event is cancelled (isCancelled=true). W12A will sync status.' } });
    continue;
  }

  const attendees = Array.isArray(liveEvent.attendees) ? liveEvent.attendees : [];
  const leadAttendee = attendees.find(a => {
    const addr = String(a.emailAddress?.address || '').trim().toLowerCase();
    return addr === leadEmail && !INTERNAL_EMAILS.includes(addr);
  });

  if (!leadAttendee) {
    results.push({ json: { noEligible: true, skipReason: '24h guard: lead ' + leadEmail + ' not found in Outlook attendees (' + attendees.length + ' total). W12A will sync.' } });
    continue;
  }

  // RSVP check removed — per current policy, non-accepted RSVPs are allowed.
  // const rsvp = String(leadAttendee.status?.response || '').trim().toLowerCase();
  // if (rsvp !== 'accepted') { ... }

  if (sfStartISO && liveEvent.start?.dateTime) {
    const sfMs = new Date(sfStartISO).getTime();
    const outlookMs = new Date(liveEvent.start.dateTime).getTime();
    const diffSec = Math.abs(sfMs - outlookMs) / 1000;
    if (diffSec > TIME_TOLERANCE_SEC) {
      results.push({ json: { noEligible: true, skipReason: '24h guard: Outlook start differs from Salesforce by ' + Math.round(diffSec) + 's — blocking. W12A will sync updated time first.' } });
      continue;
    }
  }

  results.push({ json: { ...fmt } });
}

return results.length > 0 ? results : [{ json: { noEligible: true } }];

